import React from 'react';
import { Container, Typography, Grid, Card, CardContent, CardMedia, CardActions, Button } from '@mui/material';
import GitHubIcon from '@mui/icons-material/GitHub';
import LaunchIcon from '@mui/icons-material/Launch';

const Projects = () => {
  const projects = [
    {
      title: 'Proyecto 1',
      description: 'Una aplicación web desarrollada con React y Node.js que permite a los usuarios gestionar sus tareas diarias.',
      image: '/ruta-imagen-proyecto1.jpg',
      technologies: ['React', 'Node.js', 'MongoDB'],
      github: 'https://github.com/tuusuario/proyecto1',
      demo: 'https://proyecto1-demo.com'
    },
    {
      title: 'Proyecto 2',
      description: 'Plataforma de e-commerce con sistema de pagos integrado y gestión de inventario en tiempo real.',
      image: '/ruta-imagen-proyecto2.jpg',
      technologies: ['React', 'Express', 'PostgreSQL'],
      github: 'https://github.com/tuusuario/proyecto2',
      demo: 'https://proyecto2-demo.com'
    },
    // Agrega más proyectos según necesites
  ];

  return (
    <Container maxWidth="lg" sx={{ mt: 4 }}>
      <Typography variant="h4" gutterBottom align="center" sx={{ mb: 4 }}>
        Mis Proyectos
      </Typography>
      
      <Grid container spacing={4}>
        {projects.map((project, index) => (
          <Grid item key={index} xs={12} md={6} lg={4}>
            <Card sx={{ height: '100%', display: 'flex', flexDirection: 'column' }}>
              <CardMedia
                component="img"
                height="200"
                image={project.image}
                alt={project.title}
              />
              <CardContent sx={{ flexGrow: 1 }}>
                <Typography gutterBottom variant="h5" component="h2">
                  {project.title}
                </Typography>
                <Typography>
                  {project.description}
                </Typography>
                <Typography variant="body2" color="text.secondary" sx={{ mt: 2 }}>
                  Tecnologías: {project.technologies.join(', ')}
                </Typography>
              </CardContent>
              <CardActions>
                <Button size="small" startIcon={<GitHubIcon />} href={project.github} target="_blank">
                  GitHub
                </Button>
                <Button size="small" startIcon={<LaunchIcon />} href={project.demo} target="_blank">
                  Demo
                </Button>
              </CardActions>
            </Card>
          </Grid>
        ))}
      </Grid>
    </Container>
  );
};

export default Projects;
